mapper.select:
SELECT DISTINCT u.*,i.name item_name
FROM item_units u
JOIN items i ON i.id=u.item_id
JOIN inventory_flow_item_units fx ON fx.item_unit_id=u.id AND fx.inventory_flow_id=#{flowId}
WHERE u.deleted_at IS NULL
AND u.item_id=#{itemId}
AND i.name LIKE CONCAT(#{itemName},'%')
AND u.stock_status=#{stockStatus}
AND u.quality_status=#{qualityStatus}
AND u.engineering_order_id=#{orderId}
ORDER BY u.updated_at DESC,u.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT DISTINCT f.*
FROM inventory_flows f
LEFT JOIN inventory_flow_items fi ON fi.inventory_flow_id=f.id AND fi.deleted_at IS NULL
LEFT JOIN items i ON i.id=fi.item_id
WHERE f.deleted_at IS NULL
AND f.to_user_id=#{userId}
AND f.from_user_id=#{userId}
AND f.flow_status=#{status}

  AND (f.flow_status!=1 OR f.from_user_id=#{draftOwnerUserId})

AND f.name LIKE CONCAT(#{name},'%')
AND EXISTS (SELECT 1 FROM inventory_flow_item_units fx WHERE fx.inventory_flow_id=f.id AND fx.item_unit_id=#{itemUnitId})
ORDER BY f.updated_at DESC,f.id DESC LIMIT #{limit} OFFSET #{offset}
